from flask import Flask, request, session, redirect, url_for
import xml.etree.ElementTree as ET

app = Flask(__name__)
app.secret_key = 'your_secret_key'

@app.route('/acs', methods=['POST'])
def acs():
    saml_response_xml = request.form['SAMLResponse']
    root = ET.fromstring(saml_response_xml)
    
    # Validate that assertions are present
    assertions = root.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion')
    if not assertions:
        return 'No assertion found in SAML response', 400
    
    for assertion in assertions:
        # Extract user attributes from Assertion elements
        name_id = assertion.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}NameID').text
        session['user'] = {'name_id': name_id}
        
        # Additional attribute extraction can be done here
        # For example:
        # attributes = assertion.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Attribute')
